 i < frame_len ;
 i ++ ) s -> lsp_cos_table [ i ] = 2.0f * cos ( wdel * i ) ;
 for ( i = 0 ;
 i < 256 ;
 i ++ ) {
 e = i - 126 ;
 s -> lsp_pow_e_table [ i ] = pow ( 2.0 , e * - 0.25 ) ;
 }
 b = 1.0 ;
