 st -> use_timer = 0 ;
 }
 break ;
 case TLS_ST_SW_CHANGE : s -> session -> cipher = s -> s3 -> tmp . new_cipher ;
 if ( ! s -> method -> ssl3_enc -> setup_key_block ( s ) ) {
 ossl_statem_set_error ( s ) ;
